#include <iostream>
#include <vector>
#include <climits>

using namespace std;

class Solution {
  public:
  int findMinCoins(vector<vector<int>>& grid, int m, int n) {
    vector<vector<int>> dp(m, vector<int>(n, -1));
    dp[0][0] = 0;
    for (int i = 0; i < m; i++) {
      for (int j = 0; j < n; j++) {
        if (i == 0 && j == 0) continue;
        if (dp[i-1][j] == -1 || dp[i][j-1] == -1) {}
        else {
          dp[i][j] = min(dp[i-1][j], dp[i][j-1]) + 1;
        }
      }
    }
    return dp[m-1][n-1];
  }
};

int main() {
  ios_base::sync_with_stdio(false);
  cin.tie(0);
  int t;
  cin >> t;
  while (t-- > 0) {
    int m;
    cin >> m;
    vector<vector<int>> grid(m);
    for (int i = 0; i < m; i++) {
      for (int j = 0; j < n; j++) {
        cin >> grid[i][j];
      }
    }
    int n = grid[0].size();
    cout << Solution().findMinCoins(grid, m, n) << endl;
  }
  return 0;
}
